import os
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetShotBySequenceNode(BaseNode):
    name = "Prism: Get Shot by Sequence"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("sequence", "dict")
        self.add_input("name", "string", widget_type="text", default="")
        self.add_output("shot", "dict")
        self.add_output("entity", "dict")
        self.add_output("found", "bool")

    def _get_sequences_and_shots(self, core):
        result = core.entities.getShots()
        try:
            sequences, shots = result
            return list(sequences or []), list(shots or [])
        except (TypeError, ValueError):
            shots = list(result or [])
            sequences = list(dict.fromkeys(str(s.get('sequence', '')) for s in shots if s.get('sequence')))
            return sequences, shots

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        sequence = inputs.get('sequence') or {}
        name = (inputs.get('name') or '').strip()
        empty = {'shot': {}, 'entity': {}, 'found': False}
        if core is None:
            self.log_error('No PrismCore found.')
            return empty
        if not sequence:
            self.log_error('No sequence provided.')
            return empty
        if not name:
            self.log_error('No shot name provided.')
            return empty
        prj_path = sequence.get('project_path', '')
        seq_name = sequence.get('name', '')
        if not prj_path:
            self.log_error('Sequence dict is missing project_path. Connect from prism_get_sequence_by_project.')
            return empty
        try:
            core.changeProject(prj_path)
        except Exception as e:
            self.log_error(f'changeProject failed: {e}')
            return empty
        try:
            _, shots = self._get_sequences_and_shots(core)
        except Exception as e:
            self.log_error(f'getShots failed: {e}')
            return empty
        if seq_name:
            seq_lower = seq_name.lower()
            shots = [s for s in shots if str(s.get('sequence', '')).lower() == seq_lower]
        name_lower = name.lower()
        for s in shots:
            shot_val = str(s.get('shot', s.get('name', '')))
            if shot_val.lower() == name_lower:
                entity = {'type': 'shot', 'sequence': seq_name, 'shot': shot_val}
                self.log_info(f"Found shot '{seq_name}/{shot_val}'")
                return {'shot': s, 'entity': entity, 'found': True}
        self.log_error(f"Shot '{name}' not found in {len(shots)} shot(s) of sequence '{seq_name}'.")
        return empty

def register_node():
    return PrismGetShotBySequenceNode
